// GetPokemonSprite returns the ASCII art for a Pokemon
func GetPokemonSprite(name string) string {
    if sprite, ok := PokemonSprites[name]; ok {
        return sprite
    }
    return ""
}

// ListAllPokemon returns a list of all available Pokemon
func ListAllPokemon() []string {
    names := make([]string, 0, len(PokemonSprites))
    for name := range PokemonSprites {
        names = append(names, name)
    }
    return names
}
